"use client";

import { useState, useEffect } from "react";
import { useParams } from "next/navigation";
import { fetchStockPrice, fetchStockChart, fetchStockAnalysis } from "@/lib/api";
import { addWatchlist, removeWatchlist, isInWatchlist } from "@/lib/watchlist";
import { supabase } from "@/utils/supabase/client";
import type { StockPrice, ChartResponse, StockAnalysis } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import StockChart from "@/components/stock/StockChart";
import Link from "next/link";
import { ArrowLeft, TrendingUp, TrendingDown, Minus, Sparkles, Star } from "lucide-react";

export default function StockDetailPage() {
  const { code } = useParams<{ code: string }>();
  const [price, setPrice] = useState<StockPrice | null>(null);
  const [chart, setChart] = useState<ChartResponse | null>(null);
  const [analysis, setAnalysis] = useState<StockAnalysis | null>(null);
  const [period, setPeriod] = useState("3m");
  const [loading, setLoading] = useState(true);
  const [analyzing, setAnalyzing] = useState(false);
  const [error, setError] = useState("");
  const [inWatchlist, setInWatchlist] = useState(false);
  const [watchlistLoading, setWatchlistLoading] = useState(false);
  const [userChecked, setUserChecked] = useState(false);
  const [isLoggedIn, setIsLoggedIn] = useState(false);

  useEffect(() => {
    setLoading(true);
    setError("");
    Promise.all([
      fetchStockPrice(code),
      fetchStockChart(code, period),
    ])
      .then(([p, c]) => { setPrice(p); setChart(c); })
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  }, [code, period]);

  useEffect(() => {
    supabase.auth.getUser().then(({ data: { user } }) => {
      setUserChecked(true);
      setIsLoggedIn(!!user);
      if (user) isInWatchlist(code).then(setInWatchlist);
    });
  }, [code]);

  const toggleWatchlist = () => {
    if (!price) return;
    setWatchlistLoading(true);
    (inWatchlist ? removeWatchlist(code) : addWatchlist(code, price.name))
      .then((res) => {
        if (res.ok) setInWatchlist(!inWatchlist);
        else if (res.error) setError(res.error);
      })
      .finally(() => setWatchlistLoading(false));
  };

  const loadAnalysis = () => {
    setAnalyzing(true);
    fetchStockAnalysis(code)
      .then(setAnalysis)
      .catch(() => {})
      .finally(() => setAnalyzing(false));
  };

  if (loading) return <LoadingSpinner />;
  if (error) return <ErrorMessage message={error} />;
  if (!price) return null;

  const changeColor = price.change_rate > 0 ? "text-green-400" : price.change_rate < 0 ? "text-red-400" : "text-gray-400";
  const ChangeIcon = price.change_rate > 0 ? TrendingUp : price.change_rate < 0 ? TrendingDown : Minus;

  return (
    <div className="space-y-6 max-w-2xl mx-auto">
      <Link href="/stock" className="inline-flex items-center text-gray-400 hover:text-white text-sm transition-colors">
        <ArrowLeft className="w-4 h-4 mr-1" /> 검색으로
      </Link>

      {/* 종목 기본 정보 */}
      <div className="bg-white/5 border border-white/10 rounded-xl p-6">
        <div className="flex justify-between items-start">
          <div>
            <div className="flex items-center gap-2">
              <h1 className="text-2xl font-bold">{price.name}</h1>
              {userChecked && (
                isLoggedIn ? (
                  <button
                    type="button"
                    onClick={toggleWatchlist}
                    disabled={watchlistLoading}
                    className={`p-1.5 rounded-lg transition-colors ${
                      inWatchlist
                        ? "bg-amber-500/20 text-amber-400"
                        : "bg-white/10 text-gray-400 hover:text-amber-400"
                    }`}
                    title={inWatchlist ? "관심 종목 해제" : "관심 종목 추가"}
                  >
                    <Star className={`w-5 h-5 ${inWatchlist ? "fill-current" : ""}`} />
                  </button>
                ) : (
                  <Link
                    href="/login"
                    className="p-1.5 rounded-lg bg-white/10 text-gray-400 hover:text-amber-400 transition-colors"
                    title="로그인하면 관심 종목에 추가할 수 있어요"
                  >
                    <Star className="w-5 h-5" />
                  </Link>
                )
              )}
            </div>
            <p className="text-sm text-gray-400">{price.code}</p>
          </div>
          <div className="text-right">
            <p className="text-3xl font-bold">{price.current_price.toLocaleString()}<span className="text-sm text-gray-400">원</span></p>
            <div className={`flex items-center justify-end gap-1 ${changeColor}`}>
              <ChangeIcon className="w-4 h-4" />
              <span className="font-medium">
                {price.change > 0 ? "+" : ""}{price.change.toLocaleString()}
                ({price.change_rate > 0 ? "+" : ""}{price.change_rate}%)
              </span>
            </div>
          </div>
        </div>
        <div className="grid grid-cols-3 gap-4 mt-4 pt-4 border-t border-white/10 text-sm">
          <div>
            <p className="text-gray-400">고가</p>
            <p className="font-medium">{price.high.toLocaleString()}</p>
          </div>
          <div>
            <p className="text-gray-400">저가</p>
            <p className="font-medium">{price.low.toLocaleString()}</p>
          </div>
          <div>
            <p className="text-gray-400">거래량</p>
            <p className="font-medium">{price.volume.toLocaleString()}</p>
          </div>
        </div>
      </div>

      {/* 차트 기간 선택 */}
      <div>
        <div className="flex gap-2 mb-3">
          {["1m", "3m", "6m", "1y"].map((p) => (
            <button
              key={p}
              onClick={() => setPeriod(p)}
              className={`px-3 py-1 rounded-lg text-sm transition-colors ${
                period === p ? "bg-skyblue text-white" : "bg-white/5 text-gray-400 hover:text-white"
              }`}
            >
              {p === "1m" ? "1개월" : p === "3m" ? "3개월" : p === "6m" ? "6개월" : "1년"}
            </button>
          ))}
        </div>

        {/* 캔들 차트 (lightweight-charts) */}
        {chart && chart.data.length > 0 && (
          <div className="bg-white/5 border border-white/10 rounded-xl p-4">
            <StockChart data={chart.data} className="w-full" />
            <div className="flex justify-between mt-2 text-[10px] text-gray-500">
              <span>{chart.data[0]?.date}</span>
              <span>{chart.data[chart.data.length - 1]?.date}</span>
            </div>
          </div>
        )}
      </div>

      {/* AI 분석 */}
      {!analysis && !analyzing && (
        <button
          onClick={loadAnalysis}
          className="w-full py-3 bg-skyblue/20 hover:bg-skyblue/30 border border-skyblue/30 rounded-xl text-skyblue font-medium transition-colors flex items-center justify-center gap-2"
        >
          <Sparkles className="w-5 h-5" />
          쉬운 말로 풀어서 분석해 드려요
        </button>
      )}

      {analyzing && <LoadingSpinner text="쉬운 말로 정리하고 있어요..." />}

      {analysis && (
        <div className="bg-skyblue/10 border border-skyblue/30 rounded-xl p-5 space-y-4">
          <div className="flex items-center gap-2">
            <Sparkles className="w-5 h-5 text-skyblue" />
            <h2 className="font-bold text-skyblue">쉽게 보는 분석 리포트</h2>
            <span className={`ml-auto text-sm font-bold px-2 py-0.5 rounded-full ${
              analysis.sentiment === "bullish" ? "bg-green-500/20 text-green-300" :
              analysis.sentiment === "bearish" ? "bg-red-500/20 text-red-300" :
              "bg-gray-500/20 text-gray-300"
            }`}>
              {analysis.sentiment === "bullish" ? "긍정적" : analysis.sentiment === "bearish" ? "부정적" : "중립"}
            </span>
          </div>

          <div className="flex flex-wrap gap-2">
            {analysis.key_factors.map((f, i) => (
              <span key={i} className="text-xs bg-white/10 px-2 py-1 rounded-full text-gray-300">
                {f}
              </span>
            ))}
          </div>

          <div className="text-gray-200 leading-relaxed whitespace-pre-wrap text-sm">
            {analysis.ai_report}
          </div>
        </div>
      )}
    </div>
  );
}
